const cartPrices = [15.99, 20.00, 5.50];
let total = 0;

// Modern loop for arrays
for (const price of cartPrices) {
  total += price;
}
console.log(`Total: $${total}`);

// Classic for loop
for (let i = 0; i < cartPrices.length; i++) {
  // Do something with cartPrices[i]
}

